changeSet.sql:
DO $body$
BEGIN
	IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'clock_templates' AND column_name = 'station_id')
		AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'clock_templates' AND column_name = 'channel_id')
	THEN
		ALTER TABLE clock_templates ADD COLUMN channel_id UUID;
	END IF;
END $body$;

DO $body$
BEGIN
	IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'clock_templates' AND column_name = 'station_id')
	THEN
		UPDATE clock_templates ct
		SET channel_id = (SELECT c.id FROM channels c WHERE c.station_id = ct.station_id ORDER BY c.created_at LIMIT 1)
		WHERE ct.channel_id IS NULL AND EXISTS (SELECT 1 FROM channels c WHERE c.station_id = ct.station_id);
	END IF;
END $body$;

DO $body$
BEGIN
	IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'clock_templates' AND column_name = 'station_id')
	THEN
		INSERT INTO channels (id, station_id, name, channel_number, format_type, is_active, created_at, updated_at)
		SELECT DISTINCT gen_random_uuid(), ct.station_id, 'Default Channel', 1, 'LINEAR', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
		FROM clock_templates ct
		WHERE ct.channel_id IS NULL AND NOT EXISTS (SELECT 1 FROM channels c WHERE c.station_id = ct.station_id);

		UPDATE clock_templates ct
		SET channel_id = (SELECT c.id FROM channels c WHERE c.station_id = ct.station_id ORDER BY c.created_at LIMIT 1)
		WHERE ct.channel_id IS NULL;
	END IF;
END $body$;

DO $body$
BEGIN
	IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'clock_templates' AND column_name = 'channel_id')
	THEN
		IF EXISTS (SELECT 1 FROM information_schema.table_constraints WHERE constraint_name = 'fk_clock_templates_station' AND table_name = 'clock_templates')
		THEN ALTER TABLE clock_templates DROP CONSTRAINT fk_clock_templates_station; END IF;

		DROP INDEX IF EXISTS idx_clock_templates_station_id;

		IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'clock_templates' AND column_name = 'channel_id' AND is_nullable = 'YES')
		THEN ALTER TABLE clock_templates ALTER COLUMN channel_id SET NOT NULL; END IF;

		IF NOT EXISTS (SELECT 1 FROM information_schema.table_constraints WHERE constraint_name = 'fk_clock_templates_channel' AND table_name = 'clock_templates')
		THEN ALTER TABLE clock_templates ADD CONSTRAINT fk_clock_templates_channel FOREIGN KEY (channel_id) REFERENCES channels(id) ON DELETE CASCADE; END IF;

		IF NOT EXISTS (SELECT 1 FROM pg_indexes WHERE indexname = 'idx_clock_templates_channel_id' AND tablename = 'clock_templates')
		THEN CREATE INDEX idx_clock_templates_channel_id ON clock_templates(channel_id); END IF;

		IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'clock_templates' AND column_name = 'station_id')
		THEN ALTER TABLE clock_templates DROP COLUMN station_id; END IF;
	END IF;
END $body$;
